  1→"use client";
  2→
  3→import type {
  4→  DashboardGroup,
  5→  FilterSpec,
  6→  PanelDescriptor,
  7→} from "@/components/shared/dashboard/dashboard-model";
  8→import DashboardPage from "@/components/shared/dashboard/dashboard-page";
  9→import { Button } from "@/components/ui/button";
 10→import { Input } from "@/components/ui/input";
 11→import {
 12→  DropdownMenu,
 13→  DropdownMenuContent,
 14→  DropdownMenuItem,
 15→  DropdownMenuTrigger,
 16→} from "@/components/ui/dropdown-menu";
 17→import {
 18→  Check,
 19→  Edit2,
 20→  Filter,
 21→  Pencil,
 22→  Plus,
 23→  Trash2,
 24→  X,
 25→} from "lucide-react";
 26→import { memo, useCallback, useEffect, useMemo, useState } from "react";
 27→import { DashboardFilterConfigDialog } from "./dashboard-filter-config-dialog";
 28→import {
 29→  CustomDashboardStorage,
 30→  type CustomDashboardConfig,
 31→} from "./custom-dashboard-storage";
 32→import { PanelConfigDialog } from "./panel-config-dialog";
 33→import { TabManager } from "@/components/tab-manager";
 34→import {
 35→  CustomDashboardContext,
 36→  type CustomDashboardPanelActions,
 37→} from "./custom-dashboard-context";
 38→
 39→interface CustomDashboardTabProps {
 40→  dashboardId: string;
 41→  dashboardName?: string;
 42→}
 43→
 44→const CustomDashboardTabComponent = ({
 45→  dashboardId,
 46→  dashboardName,
 47→}: CustomDashboardTabProps) => {
 48→  const storage = CustomDashboardStorage.getInstance();
 49→
 50→  // Load dashboard config from storage
 51→  const [config, setConfig] = useState<CustomDashboardConfig | null>(null);
 52→  const [isEditing, setIsEditing] = useState(false);
 53→  const [editingName, setEditingName] = useState("");
 54→  const [showPanelDialog, setShowPanelDialog] = useState(false);
 55→  const [showFilterDialog, setShowFilterDialog] = useState(false);
 56→  const [editingPanel, setEditingPanel] = useState<PanelDescriptor | null>(null);
 57→  const [editingPanelIndex, setEditingPanelIndex] = useState<number>(-1);
 58→  const [editingFilter, setEditingFilter] = useState<FilterSpec | null>(null);
 59→  const [editingFilterIndex, setEditingFilterIndex] = useState<number>(-1);
 60→
 61→  // Track the rendered dashboard key to force re-render after edits
 62→  const [dashboardKey, setDashboardKey] = useState(0);
 63→
 64→
 65→  // Load from storage on mount
 66→  useEffect(() => {
 67→    const loaded = storage.get(dashboardId);
 68→    if (loaded) {
 69→      setConfig(loaded);
 70→      setEditingName(loaded.name);
 71→    } else {
 72→      // Dashboard not found - create a new one
 73→      const newConfig = storage.createNew(dashboardName ?? "Untitled Dashboard");
 74→      // Update the ID to match
 75→      newConfig.id = dashboardId;
 76→      storage.save(newConfig);
 77→      setConfig(newConfig);
 78→      setEditingName(newConfig.name);
 79→      setIsEditing(true);
 80→    }
 81→  }, [dashboardId, dashboardName, storage]);
 82→
 83→  // Save config to storage (forces dashboard re-render for structural changes)
 84→  const saveConfig = useCallback(
 85→    (updatedConfig: CustomDashboardConfig) => {
 86→      storage.save(updatedConfig);
 87→      setConfig(updatedConfig);
 88→      setDashboardKey((k) => k + 1);
 89→    },
 90→    [storage]
 91→  );
 92→
 93→  // Handle name edit
 94→  const handleSaveName = useCallback(() => {
 95→    if (!config) return;
 96→    const trimmed = editingName.trim();
 97→    if (!trimmed) return;
 98→    const updated = { ...config, name: trimmed };
 99→    saveConfig(updated);
100→    setIsEditing(false);
101→
102→    // Update tab title
103→    TabManager.updateTabTitle(
104→      `custom-dashboard:${dashboardId}`,
105→      trimmed
106→    );
107→  }, [config, editingName, saveConfig, dashboardId]);
108→
109→  // Add panel to the first available section
110→  const handleAddPanel = useCallback(
111→    (panel: PanelDescriptor) => {
112→      if (!config) return;
113→
114→      if (editingPanelIndex >= 0) {
115→        // Update existing panel - need to find it in the correct section
116→        const updatedPanels = updatePanelAtFlatIndex(config.panels, editingPanelIndex, panel);
117→        saveConfig({ ...config, panels: updatedPanels });
118→      } else {
119→        // Add new panel to the first section
120→        const updatedPanels = addPanelToFirstSection(config.panels, panel);
121→        saveConfig({ ...config, panels: updatedPanels });
122→      }
123→      setEditingPanel(null);
124→      setEditingPanelIndex(-1);
125→    },
126→    [config, editingPanelIndex, saveConfig]
127→  );
128→
129→  // Edit panel
130→  const handleEditPanel = useCallback(
131→    (index: number) => {
132→      if (!config) return;
133→      const panels = flattenPanels(config.panels);
134→      if (index >= 0 && index < panels.length) {
135→        setEditingPanel(panels[index]);
136→        setEditingPanelIndex(index);
137→        setShowPanelDialog(true);
138→      }
139→    },
140→    [config]
141→  );
142→
143→  // Delete panel by flat index
144→  const handleDeletePanel = useCallback(
145→    (index: number) => {
146→      if (!config) return;
147→      const updatedPanels = deletePanelAtFlatIndex(config.panels, index);
148→      saveConfig({ ...config, panels: updatedPanels });
149→    },
150→    [config, saveConfig]
151→  );
152→
153→  // Add filter
154→  const handleAddFilter = useCallback(
155→    (filter: FilterSpec) => {
156→      if (!config) return;
157→      const updatedSpecs = [...config.filterSpecs, filter];
158→      saveConfig({
159→        ...config,
160→        filterSpecs: updatedSpecs,
161→        filter: {
162→          ...config.filter,
163→          selectors: [
164→            {
165→              type: "filter",
166→              name: "filters",
167→              fields: updatedSpecs,
168→            },
169→          ],
170→        },
171→      });
172→      setEditingFilter(null);
173→      setEditingFilterIndex(-1);
174→    },
175→    [config, saveConfig]
176→  );
177→
178→  // Update filter
179→  const handleUpdateFilter = useCallback(
180→    (filter: FilterSpec) => {
181→      if (!config || editingFilterIndex < 0) return;
182→      const updatedSpecs = [...config.filterSpecs];
183→      updatedSpecs[editingFilterIndex] = filter;
184→      saveConfig({
185→        ...config,
186→        filterSpecs: updatedSpecs,
187→        filter: {
188→          ...config.filter,
189→          selectors: [
190→            {
191→              type: "filter",
192→              name: "filters",
193→              fields: updatedSpecs,
194→            },
195→          ],
196→        },
197→      });
198→      setEditingFilter(null);
199→      setEditingFilterIndex(-1);
200→    },
201→    [config, editingFilterIndex, saveConfig]
202→  );
203→
204→  // Delete filter
205→  const handleDeleteFilter = useCallback(
206→    (index: number) => {
207→      if (!config) return;
208→      const updatedSpecs = config.filterSpecs.filter((_, i) => i !== index);
209→      saveConfig({
210→        ...config,
211→        filterSpecs: updatedSpecs,
212→        filter: {
213→          ...config.filter,
214→          selectors: updatedSpecs.length
215→            ? [
216→                {
217→                  type: "filter",
218→                  name: "filters",
219→                  fields: updatedSpecs,
220→                },
221→              ]
222→            : undefined,
223→        },
224→      });
225→    },
226→    [config, saveConfig]
227→  );
228→
229→
230→  // Build Dashboard model for rendering
231→  const dashboard = useMemo(() => {
232→    if (!config) return null;
233→    return CustomDashboardStorage.toDashboard(config);
234→  }, [config, dashboardKey]);
235→
236→  const allPanels = useMemo(
237→    () => (config ? flattenPanels(config.panels) : []),
238→    [config]
239→  );
240→
241→  // Context value for per-widget edit/delete actions
242→  const panelActions = useMemo<CustomDashboardPanelActions>(
243→    () => ({
244→      onEditPanel: handleEditPanel,
245→      onDeletePanel: handleDeletePanel,
246→      getPanelIndex: (descriptor) => {
247→        return allPanels.findIndex((p) => p === descriptor);
248→      },
249→    }),
250→    [handleEditPanel, handleDeletePanel, allPanels]
251→  );
252→
253→  if (!config || !dashboard) {
254→    return (
255→      <div className="flex items-center justify-center h-full text-muted-foreground">
256→        Loading dashboard...
257→      </div>
258→    );
259→  }
260→
261→  const hasPanels = allPanels.length > 0;
262→
263→  return (
264→    <div className="flex flex-col h-full w-full overflow-hidden">
265→      {/* Toolbar */}
266→      <div className="flex items-center gap-2 px-3 py-2 border-b bg-background shrink-0">
267→        {/* Dashboard name */}
268→        {isEditing ? (
269→          <div className="flex items-center gap-1">
270→            <Input
271→              value={editingName}
272→              onChange={(e) => setEditingName(e.target.value)}
273→              className="h-7 w-48 text-sm"
274→              autoFocus
275→              onKeyDown={(e) => {
276→                if (e.key === "Enter") handleSaveName();
277→                if (e.key === "Escape") {
278→                  setEditingName(config.name);
279→                  setIsEditing(false);
280→                }
281→              }}
282→            />
283→            <Button variant="ghost" size="icon" className="h-7 w-7" onClick={handleSaveName}>
284→              <Check className="h-3.5 w-3.5" />
285→            </Button>
286→            <Button
287→              variant="ghost"
288→              size="icon"
289→              className="h-7 w-7"
290→              onClick={() => {
291→                setEditingName(config.name);
292→                setIsEditing(false);
293→              }}
294→            >
295→              <X className="h-3.5 w-3.5" />
296→            </Button>
297→          </div>
298→        ) : (
299→          <button
300→            className="flex items-center gap-1.5 text-sm font-medium hover:bg-muted/50 px-2 py-1 rounded transition-colors"
301→            onClick={() => setIsEditing(true)}
302→          >
303→            {config.name}
304→            <Pencil className="h-3 w-3 text-muted-foreground" />
305→          </button>
306→        )}
307→
308→        <div className="flex-1" />
309→
310→        {/* Add filter */}
311→        <Button
312→          variant="outline"
313→          size="sm"
314→          className="h-7 text-xs gap-1"
315→          onClick={() => {
316→            setEditingFilter(null);
317→            setEditingFilterIndex(-1);
318→            setShowFilterDialog(true);
319→          }}
320→        >
321→          <Filter className="h-3.5 w-3.5" />
322→          Add Filter
323→        </Button>
324→
325→        {/* Add panel */}
326→        <Button
327→          variant="outline"
328→          size="sm"
329→          className="h-7 text-xs gap-1"
330→          onClick={() => {
331→            setEditingPanel(null);
332→            setEditingPanelIndex(-1);
333→            setShowPanelDialog(true);
334→          }}
335→        >
336→          <Plus className="h-3.5 w-3.5" />
337→          Add Panel
338→        </Button>
339→      </div>
340→
341→      {/* Filter chips bar (when filters exist) */}
342→      {config.filterSpecs.length > 0 && (
343→        <div className="flex items-center gap-1.5 px-3 py-1.5 border-b bg-muted/30 shrink-0 flex-wrap">
344→          <span className="text-xs text-muted-foreground mr-1">Filters:</span>
345→          {config.filterSpecs.map((spec, index) => (
346→            <div
347→              key={index}
348→              className="flex items-center gap-1 px-2 py-0.5 rounded-full bg-background border text-xs"
349→            >
350→              <span>{spec.displayText}</span>
351→              <button
352→                className="hover:text-foreground text-muted-foreground"
353→                onClick={() => {
354→                  setEditingFilter(spec);
355→                  setEditingFilterIndex(index);
356→                  setShowFilterDialog(true);
357→                }}
358→              >
359→                <Edit2 className="h-3 w-3" />
360→              </button>
361→              <button
362→                className="hover:text-destructive text-muted-foreground"
363→                onClick={() => handleDeleteFilter(index)}
364→              >
365→                <X className="h-3 w-3" />
366→              </button>
367→            </div>
368→          ))}
369→        </div>
370→      )}
371→
372→      {/* Dashboard content */}
373→      <div className="flex-1 min-h-0 overflow-hidden">
374→        <CustomDashboardContext.Provider value={panelActions}>
375→          {hasPanels ? (
376→            <DashboardPage
377→              dashboardId={`custom-dashboard-${dashboardKey}`}
378→              key={dashboardKey}
379→              panels={dashboard}
380→              filterSpecs={config.filterSpecs}
381→              showTimeSpanSelector={config.filter.showTimeSpanSelector}
382→              showRefresh={config.filter.showRefresh}
383→              headerActions={
384→                <PanelEditOverlay
385→                  panels={allPanels}
386→                  onEditPanel={handleEditPanel}
387→                  onDeletePanel={handleDeletePanel}
388→                />
389→              }
390→            />
391→          ) : (
392→            <EmptyDashboardState
393→              onAddPanel={() => {
394→                setEditingPanel(null);
395→                setEditingPanelIndex(-1);
396→                setShowPanelDialog(true);
397→              }}
398→            />
399→          )}
400→        </CustomDashboardContext.Provider>
401→      </div>
402→
403→      {/* Dialogs */}
404→      <PanelConfigDialog
405→        open={showPanelDialog}
406→        onOpenChange={setShowPanelDialog}
407→        onSave={handleAddPanel}
408→        editingPanel={editingPanel}
409→      />
410→
411→      <DashboardFilterConfigDialog
412→        open={showFilterDialog}
413→        onOpenChange={setShowFilterDialog}
414→        onAdd={handleAddFilter}
415→        editingFilter={editingFilter}
416→        onUpdate={handleUpdateFilter}
417→      />
418→
419→    </div>
420→  );
421→};
422→
423→/**
424→ * Empty state when no panels are added yet
425→ */
426→function EmptyDashboardState({ onAddPanel }: { onAddPanel: () => void }) {
427→  return (
428→    <div className="h-full flex flex-col items-center justify-center text-center p-8">
429→      <div className="text-muted-foreground mb-4">
430→        <svg className="h-16 w-16 mx-auto mb-4 opacity-30" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
431→          <rect x="3" y="3" width="7" height="7" rx="1" />
432→          <rect x="14" y="3" width="7" height="7" rx="1" />
433→          <rect x="3" y="14" width="7" height="7" rx="1" />
434→          <rect x="14" y="14" width="7" height="7" rx="1" />
435→        </svg>
436→        <p className="text-sm">No panels yet. Add a panel to get started.</p>
437→      </div>
438→      <Button onClick={onAddPanel} className="gap-2">
439→        <Plus className="h-4 w-4" />
440→        Add Your First Panel
441→      </Button>
442→    </div>
443→  );
444→}
445→
446→/**
447→ * Overlay buttons that appear in the dashboard header for editing panels
448→ */
449→function PanelEditOverlay({
450→  panels,
451→  onEditPanel,
452→  onDeletePanel,
453→}: {
454→  panels: PanelDescriptor[];
455→  onEditPanel: (index: number) => void;
456→  onDeletePanel: (index: number) => void;
457→}) {
458→  if (panels.length === 0) return null;
459→
460→  return (
461→    <DropdownMenu>
462→      <DropdownMenuTrigger asChild>
463→        <Button variant="outline" size="sm" className="h-7 text-xs gap-1">
464→          <Edit2 className="h-3.5 w-3.5" />
465→          Edit Panels
466→        </Button>
467→      </DropdownMenuTrigger>
468→      <DropdownMenuContent align="end" className="w-64">
469→        {panels.map((panel, index) => (
470→          <DropdownMenuItem
471→            key={index}
472→            className="flex items-center justify-between"
473→            onSelect={(e) => e.preventDefault()}
474→          >
475→            <span className="text-sm truncate mr-2">
476→              {panel.titleOption?.title ?? `Panel ${index + 1}`}
477→            </span>
478→            <div className="flex items-center gap-1 shrink-0">
479→              <Button
480→                variant="ghost"
481→                size="icon"
482→                className="h-6 w-6"
483→                onClick={() => onEditPanel(index)}
484→              >
485→                <Pencil className="h-3 w-3" />
486→              </Button>
487→              <Button
488→                variant="ghost"
489→                size="icon"
490→                className="h-6 w-6 text-destructive hover:text-destructive"
491→                onClick={() => onDeletePanel(index)}
492→              >
493→                <Trash2 className="h-3 w-3" />
494→              </Button>
495→            </div>
496→          </DropdownMenuItem>
497→        ))}
498→      </DropdownMenuContent>
499→    </DropdownMenu>
500→  );
501→}
502→
503→/**
504→ * Check if an item is a DashboardGroup
505→ */
506→function isDashboardGroup(item: PanelDescriptor | DashboardGroup): item is DashboardGroup {
507→  return "charts" in item && Array.isArray((item as DashboardGroup).charts);
508→}
509→
510→/**
511→ * Flatten panels from dashboard config (handles groups)
512→ */
513→function flattenPanels(
514→  panels: (PanelDescriptor | DashboardGroup)[]
515→): PanelDescriptor[] {
516→  const result: PanelDescriptor[] = [];
517→  for (const item of panels) {
518→    if (isDashboardGroup(item)) {
519→      result.push(...item.charts);
520→    } else {
521→      result.push(item);
522→    }
523→  }
524→  return result;
525→}
526→
527→/**
528→ * Add a panel to the first section (DashboardGroup).
529→ * If no section exists, creates a default one.
530→ */
531→function addPanelToFirstSection(
532→  panels: (PanelDescriptor | DashboardGroup)[],
533→  newPanel: PanelDescriptor
534→): (PanelDescriptor | DashboardGroup)[] {
535→  const updatedPanels = [...panels];
536→
537→  // Find the first DashboardGroup
538→  const firstGroupIndex = updatedPanels.findIndex(isDashboardGroup);
539→
540→  if (firstGroupIndex >= 0) {
541→    // Add to existing first group
542→    const group = updatedPanels[firstGroupIndex] as DashboardGroup;
543→    updatedPanels[firstGroupIndex] = {
544→      ...group,
545→      charts: [...group.charts, newPanel],
546→    };
547→  } else {
548→    // No groups exist - create a default section with this panel
549→    const defaultSection: DashboardGroup = {
550→      title: "Default",
551→      charts: [newPanel],
552→      collapsed: false,
553→    };
554→    updatedPanels.push(defaultSection);
555→  }
556→
557→  return updatedPanels;
558→}
559→
560→/**
561→ * Update a panel at a flat index (accounting for sections)
562→ */
563→function updatePanelAtFlatIndex(
564→  panels: (PanelDescriptor | DashboardGroup)[],
565→  flatIndex: number,
566→  updatedPanel: PanelDescriptor
567→): (PanelDescriptor | DashboardGroup)[] {
568→  const result: (PanelDescriptor | DashboardGroup)[] = [];
569→  let currentFlatIndex = 0;
570→
571→  for (const item of panels) {
572→    if (isDashboardGroup(item)) {
573→      const groupCharts = [...item.charts];
574→      let foundInGroup = false;
575→
576→      for (let i = 0; i < groupCharts.length; i++) {
577→        if (currentFlatIndex === flatIndex) {
578→          groupCharts[i] = updatedPanel;
579→          foundInGroup = true;
580→        }
581→        currentFlatIndex++;
582→      }
583→
584→      result.push(foundInGroup ? { ...item, charts: groupCharts } : item);
585→    } else {
586→      if (currentFlatIndex === flatIndex) {
587→        result.push(updatedPanel);
588→      } else {
589→        result.push(item);
590→      }
591→      currentFlatIndex++;
592→    }
593→  }
594→
595→  return result;
596→}
597→
598→/**
599→ * Delete a panel at a flat index (accounting for sections)
600→ */
601→function deletePanelAtFlatIndex(
602→  panels: (PanelDescriptor | DashboardGroup)[],
603→  flatIndex: number
604→): (PanelDescriptor | DashboardGroup)[] {
605→  const result: (PanelDescriptor | DashboardGroup)[] = [];
606→  let currentFlatIndex = 0;
607→
608→  for (const item of panels) {
609→    if (isDashboardGroup(item)) {
610→      const groupCharts: PanelDescriptor[] = [];
611→
612→      for (const chart of item.charts) {
613→        if (currentFlatIndex !== flatIndex) {
614→          groupCharts.push(chart);
615→        }
616→        currentFlatIndex++;
617→      }
618→
619→      // Keep the group even if empty (user can delete section explicitly)
620→      result.push({ ...item, charts: groupCharts });
621→    } else {
622→      if (currentFlatIndex !== flatIndex) {
623→        result.push(item);
624→      }
625→      currentFlatIndex++;
626→    }
627→  }
628→
629→  return result;
630→}
631→
632→CustomDashboardTabComponent.displayName = "CustomDashboardTab";
633→
634→export const CustomDashboardTab = memo(CustomDashboardTabComponent);
635→

