381→
382→    // Wrap with layout provider if dashboardId is provided
383→    if (dashboardId) {
384→      return (
385→        <DashboardLayoutProvider dashboardId={dashboardId} defaultLayouts={defaultLayouts}>
386→          {dashboardContent}
387→        </DashboardLayoutProvider>
